To solve this problem, we need to determine the edges and their weights in the tree using the minimum number of queries. Here's a strategy to achieve this:

1. **Root the Tree**: Choose an arbitrary vertex as the root of the tree.
2. **Query Distances**: Query the distances between the root and all other vertices. This will help us determine the children of the root.
3. **Explore Children**: For each child of the root, query the distances between the child and its siblings. This will help us determine the structure of the subtree rooted at each child.
4. **Reconstruct Edges**: Using the distances obtained, we can reconstruct the edges and their weights.

Let's implement this strategy in C++.

```cpp
#include <iostream>
#include <vector>
#include <algorithm>
#include <cmath>

using namespace std;

void query(int u, int v) {
    cout << "? " << u << " " << v << endl;
    cout.flush();
}

int main() {
    int T;
    cin >> T;

    while (T--) {
        int n;
        cin >> n;

        vector<int> parent(n + 1, -1);
        vector<vector<int>> dist(n + 1, vector<int>(n + 1, -1));

        // Query distances from root to all other vertices
        int root = 1;
        for (int i = 2; i <= n; ++i) {
            query(root, i);
            cin >> dist[root][i];
        }

        // Reconstruct the tree
        for (int i = 2; i <= n; ++i) {
            if (dist[root][i] == 0) continue;
            parent[i] = root;
            for (int j = 2; j <= n; ++j) {
                if (i == j || dist[root][j] == -1) continue;
                int d = dist[root][i] + dist[root][j] - dist[i][j];
                query(i, j);
                cin >> dist[i][j];
                if (d != dist[i][j]) {
                    cout << "! " << i << " " << j << " " << d << endl;
                } else {
                    cout << "! " << i << " " << j << " " << dist[i][j] << endl;
                }
            }
        }

        // Process remaining queries to reconstruct the full tree
        for (int i = 2; i <= n; ++i) {
            for (int j = i + 1; j <= n; ++j) {
                if (dist[i][j] == -1) {
                    query(i, j);
                    cin >> dist[i][j];
                }
            }
        }

        // Print the final tree
        for (int i = 2; i <= n; ++i) {
            cout << "! " << parent[i] << " " << i << " " << dist[parent[i]][i] << endl;
        }
    }

    return 0;
}
```

This solution first roots the tree at an arbitrary vertex (1 in this case) and queries the distances from the root to all other vertices. It then reconstructs the tree by querying distances between children and their siblings. Finally, it prints the reconstructed tree with all edges and their weights.

